  `parent_id` bigint NOT NULL DEFAULT 0 COMMENT '父部门ID（0=顶级）',
  `dept_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '部门名称',
