-- ----------------------------
-- Table structure for sys_menu
-- ----------------------------
DROP TABLE IF EXISTS `sys_menu`;
CREATE TABLE `sys_menu`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `parent_id` bigint NOT NULL DEFAULT 0 COMMENT '父菜单ID（0=顶级）',
  `menu_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '菜单名称（显示在侧边栏）',
  `menu_type` tinyint NOT NULL COMMENT '类型（1目录 2菜单 3按钮）',
  `path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '路由路径（Vue Router path）',
  `component` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '组件路径（Vue component，如 system/user/index）',
  `redirect` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '重定向路径',
  `icon` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '菜单图标',
  `perms` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '权限标识（如 system:user:list）',
  `display_order` int NOT NULL DEFAULT 0 COMMENT '排序（升序）',
  `is_hidden` tinyint NOT NULL DEFAULT 0 COMMENT '是否隐藏（0显示 1隐藏）',
  `is_cache` tinyint NOT NULL DEFAULT 0 COMMENT '是否缓存（1缓存 0不缓存）',
  `is_external` tinyint NOT NULL DEFAULT 0 COMMENT '是否外链（1是 0否）',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态（1正常 0禁用）',
  `is_delete` tinyint NOT NULL DEFAULT 0 COMMENT '逻辑删除（0未删除 1已删除）',
  `create_by` bigint NOT NULL DEFAULT 0 COMMENT '创建人（0=系统操作）',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` bigint NOT NULL DEFAULT 0 COMMENT '更新人（0=系统操作）',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_parent_id`(`parent_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 55 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '菜单权限表（兼容Vue动态路由）' ROW_FORMAT = Dynamic;

